
<script>
import moment from 'moment';
import ViewScheduledetails from './ViewScheduledetails.vue';
import Pager from '../../../components/Common/Pager.vue';

export default {
    components:{
        ViewScheduledetails,
        Pager,
    },
    props: {
        emailscheduledata: null,
        IsViewScheduleDetail:false

    },
    data: function () {
        return {
            EmailScheduleData: [],
            NoRecordForTab: true,
            schedulerId:0,
            TotalRecords: 0,
            PageNumber: 1,
            PageSize: 10,
            SortBy: '',
            SortExp: ''
    
            // EmailScheduleDetails
        }
    },
    watch: {
        emailscheduledata: function (value) {
            this.EmailScheduleData = value;
            this.NoRecordForTab = (this.EmailScheduleData != null && this.EmailScheduleData.length > 0) ? false : true;
            // setTimeout("ResponsiveDataTable('table-schedule-content')", 500);
        }
    },
    methods: {
     sortdata(sortBy) {
         this.SortBy = sortBy;
    this.SortExp = this.SortExp === 'ASC' ? 'DESC' : 'ASC';
    this.$emit("sort-change", sortBy); // Notify parent to re-fetch sorted data
  },
  handlePageChange(newPage) {
      this.$emit("update-page", newPage); // Notify parent of page change
    },
        formatTimeFromDateTime(value) {
            if (value) {
                // Full date and time format
                return moment(value, "YYYY-MM-DD HH:mm:ss").format('MM/DD/YYYY h:mm A');
            }
            return '';
        },
        ViewDetail(item){
            this.schedulerId=item.SCHEDULER_ID;
            this.IsViewScheduleDetail=true;

        },
        pagerMethod: function (value) {
               
               this.PageSize = value.PageSize;
               this.PageNumber = value.PageNumber;
                 this.$emit("update-page", this.PageSize,this.PageNumber); 
           },
    },
}
</script>
<template>
    <div>
                    <div class="listing" v-if="!NoRecordForTab">
                        <div class="table-responsive tableborder customborder_lightgrey float-left crm_rightpanelmaximumscroll_table_btns">
                            <table class="table table-bordered mb-0" id="table-schedule-content" aria-describedby="emailschedule">
                                <thead class="thead-bg">
                                    <tr>
<th scope="col" @click="sortdata('Subject')"><span v-bind:class="{'text-center':true,'sort': true,'tb_headerSortUp': SortBy === 'Subject' && SortExp === 'ASC','tb_headerSortDown': SortBy === 'Subject' && SortExp === 'DESC' }">{{ $t("Subject") }}</span></th>
                                         
<th scope="col" @click="sortdata('Sender')"><span v-bind:class="{'text-center':true,'sort': true,'tb_headerSortUp': SortBy === 'Sender' && SortExp === 'ASC','tb_headerSortDown': SortBy === 'Sender' && SortExp === 'DESC' }">Sender</span></th>
                                         
 <th scope="col" @click="sortdata('SCHEDULE_DATE')"><span v-bind:class="{'text-center':true,'sort': true,'tb_headerSortUp': SortBy === 'SCHEDULE_DATE' && SortExp === 'ASC','tb_headerSortDown': SortBy === 'SCHEDULE_DATE' && SortExp === 'DESC' }">{{$t("Schedule")}}  {{$t("Date")}} </span></th>
 <th scope="col" @click="sortdata('TIMEZONE')"><span v-bind:class="{'text-center':true,'sort': true,'tb_headerSortUp': SortBy === 'TIMEZONE' && SortExp === 'ASC','tb_headerSortDown': SortBy === 'TIMEZONE' && SortExp === 'DESC' }">Time Zone </span></th>

 <th scope="col" @click="sortdata('REPLYTO')"><span v-bind:class="{'text-center':true,'sort': true,'tb_headerSortUp': SortBy === 'REPLYTO' && SortExp === 'ASC','tb_headerSortDown': SortBy === 'REPLYTO' && SortExp === 'DESC' }">{{$t("ReplyTo")}} </span></th>
 <th scope="col" @click="sortdata('SCHEDULE_EMAILS')"><span v-bind:class="{'text-center':true,'sort': true,'tb_headerSortUp': SortBy === 'SCHEDULE_EMAILS' && SortExp === 'ASC','tb_headerSortDown': SortBy === 'SCHEDULE_EMAILS' && SortExp === 'DESC' }">{{$t("Schedule")}} {{$t("Emails")}} </span></th>
 <th scope="col"><span> Action </span></th>
                                     </tr>
                                </thead>
                                <tbody>
                                    <tr v-for="(item,index) in EmailScheduleData" :key="index">
                                        <td>{{item.SUBJECT}}</td>
                                        <td>{{item.SENDER}}</td>
                                        <td>{{formatTimeFromDateTime(item.SCHEDULE_DATE) }}</td>
                                            <td>{{item.TIMEZONE }}</td>
                                        <td>{{item.REPLYTO}}</td>
                                        <td>{{item.COUNT}}</td>
                                        <td  class="text-center single-action">
   
              <a href="javascript:;" @click="ViewDetail(item)" class="actions-onclick" title="View" style="overflow: unset;"><em class="fa fa-eye action-icon "></em> <br><span class="text"></span></a>
                                        </td>
                                     
                                    </tr>
                                </tbody>
                            </table>
                        </div>
              
                    </div>
                     <Pager v-bind:numberofrecords="TotalRecords" :CurrentPageNumber="PageNumber" prev-text="Prev" first-text="First" last-text="Last" next-text="Next" v-on:SetCurrentPage="pagerMethod"></Pager>
   
                    <div v-if="NoRecordForTab" class="text-center text-danger p-4 border"> {{$t("NoRecordfound")}} </div>
                    
                    <ViewScheduledetails v-if="IsViewScheduleDetail" :schedulerId="schedulerId"></ViewScheduledetails>
            </div>
</template>