<template>
    <div>
        <template>
            <transition name="modal">
                <div class="modal d-block my-popups dialog">
                    <loader :is-visible="isLoading"></loader>

                    <div class="modal-dialog">
                        <div class="modal-content">
                            <div class="modal-header">
                                <slot name="headerForModal">
                                    <h5 class="modal-title">Schedule Details</h5>
                                </slot>
                                <button type="button" title v-on:click="closeConsent" class="close"
                                    data-original-title="Close">
                                    <em class="fa fa-times" aria-hidden="true"></em>
                                </button>
                            </div>
                            <div class="modal-body">



<div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left p-0 mb-1" v-if="scheduleddetails">
<div class="row">

    <div class="col-md-6 col-lg-4">
         <div class="form-group mb-2"><label><b>Template Name:</b> {{ scheduleddetails[0].TEMPLATE_NAME }}</label></div>
    </div>

   <div class="col-md-6 col-lg-4">
         <div class="form-group mb-2"><label><b>Subject:</b> {{ scheduleddetails[0].EMAIL_SUBJECT }}</label></div>
    </div>

    <div class="col-md-6 col-lg-4">
         <div class="form-group mb-2"><label><b>Sender:</b> {{ scheduleddetails[0].SENDER }}</label></div>
    </div>


<div class="col-md-6 col-lg-4">
         <div class="form-group mb-2"><label><b>Reply To:</b> {{ scheduleddetails[0].REPLYTO }}</label></div>
    </div>
    <div class="col-md-6 col-lg-4">
         <div class="form-group mb-2"><label><b>Tracking Code:</b> {{ scheduleddetails[0].TRACKING_CODE }}</label></div>
    </div>
    <div class="col-md-6 col-lg-4">
         <div class="form-group mb-2"><label><b>Schedule Type:</b> {{ scheduleddetails[0].SEND_TYPE }}</label></div>
    </div>

     <div class="col-md-6 col-lg-4">
         <div class="form-group mb-2"><label><b>Schedule Date:</b> {{ formatTimeFromDateTime(scheduleddetails[0].SCHEDULE_DATE) }}</label></div>
    </div>
    
    

    <div class="col-md-6 col-lg-4">
         <div class="form-group mb-2"><label><b>Mail Status:</b> {{ scheduleddetails[0].MAIL_STATUS }}</label></div>
    </div>

    <div class="col-md-6 col-lg-4">
         <div class="form-group mb-2"><label><b>Status:</b> {{ scheduleddetails[0].STATUS_NAME }}</label></div>
    </div> 

     <div class="col-md-12 col-lg-12">
         <div class="form-group mb-2"><label><b>Schedue To:</b> {{ scheduleddetails[0].EMAIL_TO }}</label></div>
    </div>
    <div class="col-md-12 col-lg-12">
         <div class="form-group mb-2"><label><b>Schedule Emails:</b> {{ scheduleddetails[0].SCHEDULED_EMAIL_COUNT }}</label></div>
    </div>
    

<div class="col-md-12 col-lg-12 mt-3" v-html="scheduleddetails[0].EMAIL_CONTENT"></div>


<div class="col-md-12 col-lg-12 mt-3 text-right">
<a v-on:click="closeConsent" tabindex="6" class="green btn btn-danger" id="btnSavereminder" title="" data-toggle-tooltip="tooltip" data-original-title="Close"><i class="fa fa-times pr-2"></i>Close</a>
</div>

</div>

</div>



                            </div>
                        </div>
                    </div>
                </div>
            </transition>
        </template>
    </div>
</template>

<script>
import moment from 'moment';
import DataService from "../../../services/DataService";

export default {
    props: {
        //
        schedulerId: {
            type: Number,
            required: false
        },
       
    },

    components: {
    },
    data() {
        return {
            isLoading: false,
            scheduleddetails:''
        };
    },

    created() {
        var vm = this;
        vm.ViewDetail();

    },
    methods: {

formatTimeFromDateTime(value) {
            if (value) {
                // Full date and time format
                return moment(value, "YYYY-MM-DD HH:mm:ss").format('MM/DD/YYYY h:mm A');
            }
            return '';
        },
   async ViewDetail() {
      const params = `scheduledId=${this.schedulerId}`;
      const response = await DataService.getScheduledCampaignDetails(params);
      this.scheduleddetails = response.data;

    },

    
   closeConsent() {
            this.$parent.IsViewScheduleDetail = false
    },
     

      


    },
};
</script>
